"use client";
import { useState, useEffect } from 'react';
import Link from 'next/link';
import { 
  History, Filter, Rocket, Flame, ArrowLeft, 
  ChevronRight, Calendar, AlertCircle, ShieldAlert 
} from 'lucide-react';
import { getStoredData, Deployment, Incident } from '@/lib/mockData';
import { getAuthToken } from '@/lib/session';

export default function TimelinePage() {
  const [timelineItems, setTimelineItems] = useState<(
    { type: 'deploy'; id: string; service: string; version: string; risk: number; status: string; time: string; timestamp: string; note: string } |
    { type: 'incident'; id: string; service: string; title: string; severity: string; status: string; time: string; timestamp: string; note: string }
  )[]>([]);

  const [serviceFilter, setServiceFilter] = useState('all');
  const [typeFilter, setTypeFilter] = useState('all'); // all, deploy, incident

  useEffect(() => {
    async function load() {
      try {
        const token = getAuthToken();
        const headers: Record<string, string> = token ? { Authorization: `Bearer ${token}` } : {};
        const [depRes, incRes] = await Promise.all([
          fetch('/api/deployments?per_page=100', { headers }),
          fetch('/api/incidents?per_page=100', { headers }),
        ]);
        const depJson = depRes.ok ? await depRes.json() : { data: [] };
        const incJson = incRes.ok ? await incRes.json() : { data: [] };

        const mappedDeps = (depJson.data ?? []).map((d: any) => ({
          type: 'deploy' as const,
          id: d.id,
          service: d.service?.name ?? d.service_id,
          version: d.version,
          risk: d.risk_score ?? 0,
          status: d.environment?.name
            ? (d.environment.name.charAt(0).toUpperCase() + d.environment.name.slice(1))
            : 'Dev',
          time: new Date(d.created_at ?? d.started_at ?? Date.now()).toLocaleString(),
          timestamp: d.created_at ?? d.started_at ?? new Date().toISOString(),
          note: d.change_summary ?? '',
        }));

        const mappedIncs = (incJson.data ?? []).map((i: any) => ({
          type: 'incident' as const,
          id: i.id,
          service: i.service ?? 'unknown',
          title: i.title,
          severity: i.severity ?? 'P3',
          status: i.status === 'resolved' ? 'Resolved' : 'Active',
          time: i.started_at ? new Date(i.started_at).toLocaleString() : 'Unknown',
          timestamp: i.created_at ?? i.started_at ?? new Date().toISOString(),
          note: i.resolution_summary ?? i.description ?? '',
        }));

        const combined = [...mappedDeps, ...mappedIncs].sort((a, b) =>
          new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
        );
        setTimelineItems(combined);
      } catch {
        // fallback to localStorage
        const data = getStoredData();
        const mappedDeps = data.deployments.map((d: Deployment) => ({
          type: 'deploy' as const, id: d.id, service: d.service, version: d.version,
          risk: d.risk, status: d.status, time: d.time, timestamp: d.timestamp, note: d.changeSummary
        }));
        const mappedIncs = data.incidents.map((i: Incident) => ({
          type: 'incident' as const, id: i.id, service: i.service, title: i.title,
          severity: i.severity, status: i.status, time: i.time, timestamp: i.timestamp, note: i.resolution
        }));
        const combined = [...mappedDeps, ...mappedIncs].sort((a, b) =>
          new Date(b.timestamp).getTime() - new Date(a.timestamp).getTime()
        );
        setTimelineItems(combined);
      }
    }
    load();
  }, []);

  const filteredItems = timelineItems.filter(item => {
    if (serviceFilter !== 'all' && item.service !== serviceFilter) return false;
    if (typeFilter === 'deploy' && item.type !== 'deploy') return false;
    if (typeFilter === 'incident' && item.type !== 'incident') return false;
    return true;
  });

  return (
    <div className="p-8 space-y-8 animate-fade-in max-w-5xl mx-auto">
      
      {/* Header */}
      <header className="flex flex-col sm:flex-row justify-between items-start sm:items-end gap-4">
        <div>
          <h1 className="text-2xl font-bold tracking-tight text-[#F0F2FF]">Operational Timeline</h1>
          <p className="text-xs text-[#8B91B5] mt-1">Unified chronology of deployments, configurations changes, and incidents</p>
        </div>

        <div className="flex items-center gap-3 w-full sm:w-auto">
          {/* Service filter selector */}
          <div className="flex items-center gap-1.5 bg-[#13161E] border border-[#2A2F45] rounded-lg px-2.5 py-1.5 w-1/2 sm:w-auto">
            <Filter size={12} className="text-[#8B91B5]" />
            <select 
              value={serviceFilter}
              onChange={(e) => setServiceFilter(e.target.value)}
              className="bg-transparent text-xs text-[#F0F2FF] focus:outline-none pr-4 w-full"
            >
              <option value="all">All Services</option>
              <option value="auth-service">auth-service</option>
              <option value="payment-service">payment-service</option>
              <option value="api-gateway">api-gateway</option>
              <option value="notification-service">notification-service</option>
            </select>
          </div>

          {/* Type filter */}
          <div className="flex items-center gap-1.5 bg-[#13161E] border border-[#2A2F45] rounded-lg px-2.5 py-1.5 w-1/2 sm:w-auto">
            <Filter size={12} className="text-[#8B91B5]" />
            <select 
              value={typeFilter}
              onChange={(e) => setTypeFilter(e.target.value)}
              className="bg-transparent text-xs text-[#F0F2FF] focus:outline-none pr-4 w-full"
            >
              <option value="all">All Events</option>
              <option value="deploy">Deployments Only</option>
              <option value="incident">Incidents Only</option>
            </select>
          </div>
        </div>
      </header>

      {/* Chronological Stream */}
      <div className="relative border-l border-[#2A2F45] ml-4 md:ml-8 pl-8 space-y-8 py-2">
        {filteredItems.length === 0 ? (
          <div className="text-center py-8 text-xs text-[#8B91B5] italic">
            No events match your filter criteria.
          </div>
        ) : (
          filteredItems.map((item, idx) => {
            const isDeploy = item.type === 'deploy';
            
            // Dot styling
            let dotBg = 'bg-[#4F7FFF]';
            let icon = <Rocket size={12} className="text-[#0D0F14]" />;
            
            if (!isDeploy) {
              dotBg = 'bg-[#EF4444]';
              icon = <Flame size={12} className="text-[#0D0F14]" />;
            } else {
              const deployItem = item as typeof timelineItems[number] & { risk: number };
              if (deployItem.risk > 80) dotBg = 'bg-[#EF4444]';
              else if (deployItem.risk > 60) dotBg = 'bg-[#F97316]';
              else if (deployItem.risk > 30) dotBg = 'bg-[#EAB308]';
              else dotBg = 'bg-[#22C55E]';
              icon = <Rocket size={12} className="text-[#0D0F14]" />;
            }

            return (
              <div key={`${item.type}-${item.id}`} className="relative animate-fade-in group">
                {/* Timeline node dot */}
                <div className={`absolute -left-[41px] top-1.5 w-6 h-6 rounded-lg ${dotBg} flex items-center justify-center shadow-lg group-hover:scale-110 transition-transform duration-200`}>
                  {icon}
                </div>

                {/* Event Card */}
                <div className="card-bg rounded-xl p-5 space-y-3 hover:border-l-[#4F7FFF] transition-all">
                  <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center gap-2">
                    <div className="flex flex-wrap items-center gap-2.5">
                      <span className="text-xs font-bold text-[#F0F2FF]">{item.service}</span>
                      
                      {isDeploy ? (
                        <>
                          <span className="text-[10px] font-mono text-[#8B91B5] bg-[#1C2030] px-1.5 py-0.5 rounded border border-[#2A2F45]">
                            {(item as any).version}
                          </span>
                          <span className={`px-2 py-0.25 rounded text-[9px] font-bold border border-transparent ${
                            (item as any).status.toLowerCase() === 'production' 
                              ? 'text-[#22C55E] bg-[#22C55E]/10' 
                              : 'text-[#4F7FFF] bg-[#4F7FFF]/10'
                          }`}>
                            {(item as any).status}
                          </span>
                        </>
                      ) : (
                        <span className="text-[9px] font-bold text-[#EF4444] bg-[#EF4444]/10 border border-[#EF4444]/20 px-2 py-0.25 rounded">
                          Incident {(item as any).severity}
                        </span>
                      )}
                    </div>

                    <div className="flex items-center gap-1.5 text-xs text-[#8B91B5]">
                      <Calendar size={12} />
                      <span>{item.time}</span>
                    </div>
                  </div>

                  <h3 className="text-xs font-bold text-[#F0F2FF]">
                    {isDeploy ? 'Deployment trigger completed' : (item as any).title}
                  </h3>

                  <p className="text-xs text-[#8B91B5] leading-relaxed italic border-t border-[#2A2F45]/50 pt-2.5">
                    "{item.note}"
                  </p>
                  
                  {isDeploy && (
                    <div className="flex justify-between items-center pt-1.5 text-[10px]">
                      <span className="text-[#8B91B5] font-medium">Risk Calculated Score: <span className="font-bold text-[#F0F2FF]">{(item as any).risk}</span></span>
                      <Link href={`/deployments/${item.id}`} className="text-[#4F7FFF] hover:underline font-bold">
                        Inspect deployment details →
                      </Link>
                    </div>
                  )}
                </div>
              </div>
            );
          })
        )}
      </div>

    </div>
  );
}
